import{o as i,c as r,j as t,n as s,ae as n,p as l}from"./chunks/framework.BSk3HXt1.js";const p={class:"language-toggle-wrapper"},h={class:"language-toggle-bar"},b=JSON.parse('{"title":"樹莓派創辦人開砲：過度神化 AI 將扼殺科技就業並損害經濟 | AI Could Put People off Tech Jobs and Hurt the Economy, Warns Raspberry Pi Boss","description":"","frontmatter":{"outline":[2,3],"title":"樹莓派創辦人開砲：過度神化 AI 將扼殺科技就業並損害經濟 | AI Could Put People off Tech Jobs and Hurt the Economy, Warns Raspberry Pi Boss"},"headers":[],"relativePath":"news/ai-hypes-jobs-raspberry-pi.md","filePath":"news/ai-hypes-jobs-raspberry-pi.md"}'),c={name:"news/ai-hypes-jobs-raspberry-pi.md"},y=Object.assign(c,{setup(d){const a=l("bilingual");return(u,e)=>(i(),r("div",null,[t("div",p,[t("div",h,[t("button",{class:s(["language-toggle-btn",{active:a.value==="bilingual"}]),onClick:e[0]||(e[0]=o=>a.value="bilingual")}," 中英雙語 (Bilingual) ",2),t("button",{class:s(["language-toggle-btn",{active:a.value==="zh"}]),onClick:e[1]||(e[1]=o=>a.value="zh")}," 純中文 (Chinese) ",2),t("button",{class:s(["language-toggle-btn",{active:a.value==="en"}]),onClick:e[2]||(e[2]=o=>a.value="en")}," 純英文 (English) ",2)])]),t("div",{class:s("bilingual-article mode-"+a.value)},[...e[3]||(e[3]=[n('<h1 id="樹莓派創辦人開砲-過度神化-ai-將扼殺科技就業並損害經濟-ai-could-put-people-off-tech-jobs-and-hurt-the-economy-warns-raspberry-pi-boss" tabindex="-1">樹莓派創辦人開砲：過度神化 AI 將扼殺科技就業並損害經濟 <br><span style="font-size:1.5rem;color:var(--vp-c-text-2);">AI Could Put People off Tech Jobs and Hurt the Economy, Warns Raspberry Pi Boss</span> <a class="header-anchor" href="#樹莓派創辦人開砲-過度神化-ai-將扼殺科技就業並損害經濟-ai-could-put-people-off-tech-jobs-and-hurt-the-economy-warns-raspberry-pi-boss" aria-label="Permalink to &quot;樹莓派創辦人開砲：過度神化 AI 將扼殺科技就業並損害經濟 &lt;br&gt;&lt;span style=&quot;font-size: 1.5rem; color: var(--vp-c-text-2);&quot;&gt;AI Could Put People off Tech Jobs and Hurt the Economy, Warns Raspberry Pi Boss&lt;/span&gt;&quot;">​</a></h1><div style="text-align:center;margin:24px 0 32px 0;"><img src="/ai-news/ai-hypes-jobs-raspberry-pi/hero.png" alt="Raspberry Pi AI Job Warning" style="border-radius:16px;max-width:100%;box-shadow:0 8px 32px rgba(0,0,0,0.15);border:1px solid rgba(255,255,255,0.08);"></div><div class="bilingual-paragraph"><p class="zh-text">英國微型電腦大廠「樹莓派（Raspberry Pi）」的創辦人警告，當前社會對人工智慧（AI）能力的極度高估，正潛移默化地勸退無數有志青年投身科技產業，最終將對實體經濟造成不可挽回的重創。</p><p class="en-text">The founder of British computer maker Raspberry Pi has warned that overestimating the abilities of Artificial Intelligence (AI) could put people off pursuing tech jobs and hurt the economy.</p></div><div class="bilingual-paragraph"><p class="zh-text">創辦人埃本·阿普頓（Eben Upton）在接受 BBC 的《大佬專訪（Big Boss Interview）》Podcast 節目時直言，這種集體焦慮可能會「扭曲人們的生涯選擇，反而讓原本就存在的科技人才荒惡化，而非改善」。</p><p class="en-text">Eben Upton told the BBC&#39;s Big Boss Interview podcast this could &quot;distort people&#39;s choices in ways that make that skill shortage worse and not better&quot;.</p></div><div class="bilingual-paragraph"><p class="zh-text">他指出，目前許多人「非常傾向於高估這些 AI 工具的實際能耐」，並嚴詞駁斥了那種「AI 將在未來數年內將程式開發與資訊工程相關職位斬盡殺絕」的末日預言。</p><p class="en-text">Some people are &quot;very inclined to overestimate what these [AI] tools can do,&quot; he said, and warned against claims that it would destroy vast numbers of computing roles over the coming years.</p></div><hr><h2 id="💼-ai-成了科技裁員潮的「代罪羔羊」-ai-as-a-corporate-scapegoat" tabindex="-1">💼 AI 成了科技裁員潮的「代罪羔羊」 (AI as a Corporate Scapegoat) <a class="header-anchor" href="#💼-ai-成了科技裁員潮的「代罪羔羊」-ai-as-a-corporate-scapegoat" aria-label="Permalink to &quot;💼 AI 成了科技裁員潮的「代罪羔羊」 (AI as a Corporate Scapegoat)&quot;">​</a></h2><div class="bilingual-paragraph"><p class="zh-text">隨著 ChatGPT 和 Claude 等生成式 AI 工具的橫空出世，市場上充斥著鋪天蓋地的失業恐慌，特別是針對科技業基層工作者與剛畢業的社會新鮮人。過去一年間，包括亞馬遜（Amazon）、Meta 以及微軟（Microsoft）在內的科技龍頭在裁撤數以萬計的員工時，也紛紛將部分原因歸咎於「因應 AI 的部門重組」。</p><p class="en-text">The rise of tools such as ChatGPT and Claude have led to predictions of huge job losses, particularly for tech workers and graduates. Amazon, Meta and Microsoft have already blamed tens of thousands of layoffs on AI over the last year.</p></div><div class="bilingual-paragraph"><p class="zh-text">然而，不少專家對此持懷疑態度，認為這項新技術實際上成了大企業用來掩蓋「新冠疫情期間非理性盲目擴張」後，被迫縮減編制的完美遮羞布與替罪羔羊。</p><p class="en-text">But some experts have suggested the technology is being used as a scapegoat for reducing headcount after a post-Covid hiring spree by many big corporates.</p></div><div class="bilingual-paragraph"><p class="zh-text">阿普頓沉痛地指出，把聊天機器人（Chatbot）取代人類的能力吹噓得過度天花亂墜，將會「徹底摧毀無數機構——包括樹莓派在內多年來好不容易建立的豐碩成果」，也就是鼓勵下一代年輕人勇敢擁抱計算科學並視其為終身事業的信心。</p><p class="en-text">Overestimating chatbots&#39; ability to replace people could &quot;undo a lot of the good work that&#39;s been done, not just by Raspberry Pi, but by a lot of other organisations&quot; in encouraging people into tech careers, Upton said.</p></div><div class="bilingual-paragraph"><p class="zh-text">他補充道：「在大家瘋狂追捧這些『確實令人驚嘆』的工具的當下，最危險的就是被這種狂熱沖昏了頭，在狂熱之中，我們正在埋下破壞未來的隱憂。」</p><p class="en-text">He added: &quot;It&#39;s possible to get caught up in this. This is the risk of damage right in this moment of incredible enthusiasm for what are genuinely incredible tools.&quot;</p></div><hr><h2 id="📚-教育指引的迷茫-等五年後再說-educating-the-next-generation" tabindex="-1">📚 教育指引的迷茫：等五年後再說 (Educating the Next Generation) <a class="header-anchor" href="#📚-教育指引的迷茫-等五年後再說-educating-the-next-generation" aria-label="Permalink to &quot;📚 教育指引的迷茫：等五年後再說 (Educating the Next Generation)&quot;">​</a></h2><div class="bilingual-paragraph"><p class="zh-text">「你常在報紙上看到這樣的聳動標題：『在人工智慧的主宰未來，你該指導你的孩子去選修哪些中學會考課程（GCSE）？』」阿普頓諷刺地說道。「事實上是，我們現在根本沒有任何客觀數據能做出這種『理性的判斷』。」</p><p class="en-text">&quot;You read in the paper: &#39;What guidance should you give your child about what GCSEs to choose in the context of an AI future?&#39; We have no data to inform a rational decision on that.</p></div><div class="bilingual-paragraph"><p class="zh-text">「真正的標準答案應該是：耐心等個 5 年、10 年，到時候大局底定，我們或許才能真正明白人工智慧對教育和職能的影響究竟在哪裡。」</p><p class="en-text">&quot;The answer is: wait five years, wait 10 years, and then maybe we might know something.&quot;</p></div><div class="bilingual-paragraph"><p class="zh-text">當被主持人問及這股恐慌是否會扼殺經濟增長時，阿普頓毫不猶豫地給出了肯定答覆：「絕對會。因為無論在任何時代，我們的經濟都需要源源不斷的優秀工程師來支撐推動。」</p><p class="en-text">Asked if the phenomenon could damage economic growth, he added: &quot;Absolutely. We need a supply of engineers.&quot;</p></div><hr><h2 id="🍓-樹莓派-從非營利到百億股市神話-raspberry-pi-s-legendary-journey" tabindex="-1">🍓 樹莓派：從非營利到百億股市神話 (Raspberry Pi&#39;s Legendary Journey) <a class="header-anchor" href="#🍓-樹莓派-從非營利到百億股市神話-raspberry-pi-s-legendary-journey" aria-label="Permalink to &quot;🍓 樹莓派：從非營利到百億股市神話 (Raspberry Pi&#39;s Legendary Journey)&quot;">​</a></h2><div class="bilingual-paragraph"><p class="zh-text">樹莓派所生產的微型電腦不僅是全英國銷量最亮眼的電腦品牌，更在無數硬體極客與自學編程的愛好者心中擁有圖騰般的崇高地位。</p><p class="en-text">Raspberry Pi&#39;s devices are the most widely sold computers by a UK firm and are popular with people who do programming as a hobby.</p></div><div class="bilingual-paragraph"><p class="zh-text">阿普頓於 2012 年一手創立了這家非營利轉型的企業。當時他極度憂慮，隨著智慧型手機與家用遊戲機全面主宰青少年的感官娛樂，下一代正逐漸失去底層的運算思維和硬體寫入能力，因為現代設備把軟體與硬體層層封裝，不再像早年的電腦那樣能讓人輕易拆卸並編寫底層代碼。</p><p class="en-text">Upton founded the company in 2012 because he was concerned young people were no longer getting computing skills because mobile phones and games consoles were replacing devices that they easily programme.</p></div><div class="bilingual-paragraph"><p class="zh-text">2024 年，樹莓派在倫敦證券交易所（LSE）風光掛牌上市。在近期眾多本土科技明珠（如總部位於劍橋的頂級晶片架構商 ARM）集體出走、轉奔美國納斯達克掛牌的低迷氛圍下，樹莓派的成功上市，為死氣沉沉的英國股市注入了一劑振奮人心的強心針。</p><p class="en-text">Raspberry Pi floated on the London Stock Exchange in 2024 and has become a success story for the UK stock market amid a swathe of other firms snubbing it for a listing in the US, including Cambridge-based chip maker Arm.</p></div><hr><h2 id="⚡-英國工業復興的真正痛點-高昂能源-the-true-industrial-bottleneck" tabindex="-1">⚡ 英國工業復興的真正痛點：高昂能源 (The True Industrial Bottleneck) <a class="header-anchor" href="#⚡-英國工業復興的真正痛點-高昂能源-the-true-industrial-bottleneck" aria-label="Permalink to &quot;⚡ 英國工業復興的真正痛點：高昂能源 (The True Industrial Bottleneck)&quot;">​</a></h2><div class="bilingual-paragraph"><p class="zh-text">阿普頓表示，雖然英國擁有「龐大」且紮實的工業製造與設計潛能，但他不得不承認，在英國本土設廠，高不可攀的能源成本依舊是製造業面臨的最大「生死考驗」。</p><p class="en-text">Upton said that while the UK had &quot;enormous&quot; industrial capacity, he admitted that high energy costs are &quot;a challenge&quot; for firms.</p></div><div class="bilingual-paragraph"><p class="zh-text">近年來，英國的工業與民用電價在七大工業國集團（G7）中長年名列前茅，這對本土的製造業產生了顯著的排擠與傷害效應。</p><p class="en-text">Britain has had among highest energy costs of the G7 nations in recent years, which has proved damaging for businesses.</p></div><div class="bilingual-paragraph"><p class="zh-text">「如果說有什麼唯一的理由能阻止我在英國本地搞工程硬體實體製造，那絕對是這令人髮指的能源代價。政府必須對此採取雷厲風行的措施，」阿普頓犀利地點出，「我們已經算是極度走運，因為樹莓派不需要運營一座耗電極巨的化肥廠或煉油廠。」</p><p class="en-text">&quot;About the only reason I wouldn&#39;t do engineering build objects in the UK is the high cost of energy, and we need to do something about that,&quot; Upton said. &quot;We&#39;re extremely lucky we&#39;re not running a fertiliser factory or an oil refinery.&quot;</p></div><div class="bilingual-paragraph"><p class="zh-text">「家庭的能源開銷暴漲，也會立刻投射在企業的勞務成本上——因為如果基本水電燃氣都貴得離譜，你身為老闆，就不得不付給員工更多薪水，讓他們能體面地在本地活下去。」</p><p class="en-text">&quot;The cost of energy in the home has an impact on your labour cost. You have to pay people enough money to live.&quot;</p></div><div class="original-source-wrapper"><div class="source-label"><span class="zh-text">🌐 閱讀英文原文：</span><span class="en-text">🌐 Read Original Article:</span></div><a href="https://www.bbc.com/news/articles/clypr8p2lewo" target="_blank" rel="noopener noreferrer" class="source-link-btn"> BBC News <span style="font-size:0.8rem;">↗</span></a></div>',28)])],2)]))}});export{b as __pageData,y as default};
